package com.bluesoft.pawmarket.service;import com.bluesoft.pawmarket.dto.OrdenDetalleRequestDTO;import com.bluesoft.pawmarket.dto.OrdenRequestDTO;import com.bluesoft.pawmarket.dto.OrdenResponseDTO;import com.bluesoft.pawmarket.entity.Orden;import com.bluesoft.pawmarket.entity.OrdenDetalle;import com.bluesoft.pawmarket.entity.Producto;import com.bluesoft.pawmarket.entity.Usuario;import com.bluesoft.pawmarket.exception.BusinessException;import com.bluesoft.pawmarket.exception.ResourceNotFoundException;import com.bluesoft.pawmarket.mapper.OrdenMapper;import com.bluesoft.pawmarket.repository.OrdenRepository;import com.bluesoft.pawmarket.repository.ProductoRepository;import com.bluesoft.pawmarket.repository.UsuarioRepository;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.Page;import org.springframework.data.domain.Pageable;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;import java.util.List;@Service@RequiredArgsConstructorpublic class OrdenServiceImpl implements OrdenService {    private final OrdenRepository ordenRepository;    private final UsuarioRepository usuarioRepository;    private final ProductoRepository productoRepository;    private final OrdenMapper ordenMapper;    @Override    @Transactional    public OrdenResponseDTO crear(OrdenRequestDTO dto) {        Usuario usuario = usuarioRepository.findById(dto.getUsuarioId()).orElseThrow(() ->                new ResourceNotFoundException("No se encontró el usuario con id: " + dto.getUsuarioId()));        if (!usuario.isActivo()) {            throw new BusinessException("El usuario no está activo");        }        Orden orden = ordenMapper.toEntity(usuario);        for (OrdenDetalleRequestDTO item : dto.getItems()) {            Producto producto = productoRepository.findById(item.getProductoId()).orElseThrow(                    () -> new ResourceNotFoundException("No se encontró el producto con id: " + item.getProductoId()));            validarProductoParaOrden(producto, item.getCantidad());            OrdenDetalle ordenDetalle = ordenMapper.toDetalleEntity(item, producto, orden);            ordenDetalle.setPrecioUnitario(producto.getPrecio());            ordenDetalle.setSubtotal(producto.getPrecio().multiply(BigDecimal.valueOf(item.getCantidad())));            orden.getDetalles().add(ordenDetalle);            descontarStock(producto, item.getCantidad());        }        orden.setTotal(calcularTotal(orden.getDetalles()));        Orden guardada = ordenRepository.save(orden);        return ordenMapper.toResponseDTO(guardada);    }    @Override    @Transactional(readOnly = true)    public OrdenResponseDTO buscarPorId(Long id) {        Orden orden = ordenRepository.findByIdWithDetalles(id).orElseThrow(                () -> new ResourceNotFoundException("No se encontró la orden con id: " + id));        return ordenMapper.toResponseDTO(orden);    }    @Override    @Transactional(readOnly = true)    public Page<OrdenResponseDTO> listar(Pageable pageable) {        return ordenRepository.findAll(pageable).map(ordenMapper::toResponseDTO);    }    @Override    @Transactional(readOnly = true)    public Page<OrdenResponseDTO> listarPorUsuario(Long usuarioId, Pageable pageable) {        if (!usuarioRepository.existsById(usuarioId)) {            throw new ResourceNotFoundException("No se encontró el usuario con id: " + usuarioId);        }        return ordenRepository.findByUsuario_Id(usuarioId, pageable).map(ordenMapper::toResponseDTO);    }    @Override    @Transactional    public OrdenResponseDTO cambiarEstado(Long id, Orden.EstadoOrden estadoOrden) {        Orden orden = ordenRepository.findByIdWithDetalles(id).orElseThrow(                () -> new ResourceNotFoundException("No se encontró la orden con id: " + id));        validarTransicion(orden.getEstado(), estadoOrden);        if (estadoOrden == Orden.EstadoOrden.CANCELADA) {            restaurarStock(orden);        }        orden.setEstado(estadoOrden);        return ordenMapper.toResponseDTO(orden);    }    private void validarProductoParaOrden(Producto producto, int cantidadPedida) {        if (producto.getEstadoProducto() != Producto.EstadoProducto.ACTIVO) {            throw new BusinessException("El producto no está disponible: " + producto.getNombre());        }        if (producto.getCantidad() < cantidadPedida) {            throw new BusinessException(                    "Stock insuficiente para " + producto.getNombre()                            + ". Disponible: " + producto.getCantidad());        }    }    private void descontarStock(Producto producto, int cantidad) {        producto.setCantidad(producto.getCantidad() - cantidad);        if (producto.getCantidad() == 0) {            producto.setEstadoProducto(Producto.EstadoProducto.AGOTADO);        }    }    private void validarTransicion(Orden.EstadoOrden actual, Orden.EstadoOrden nuevo) {        if (actual == nuevo) {            throw new BusinessException("La orden ya está en estado " + nuevo);        }        switch (actual) {            case PENDIENTE -> {                if (nuevo != Orden.EstadoOrden.CONFIRMADA && nuevo != Orden.EstadoOrden.CANCELADA) {                    throw new BusinessException("Desde PENDIENTE solo se puede confirmar o cancelar");                }            }            case CONFIRMADA -> {                if (nuevo != Orden.EstadoOrden.CANCELADA) {                    throw new BusinessException("Desde CONFIRMADA solo se puede cancelar");                }            }            case CANCELADA -> throw new BusinessException("La orden ya está cancelada");        }    }    private void restaurarStock(Orden orden) {        for (OrdenDetalle detalle : orden.getDetalles()) {            Producto producto = detalle.getProducto();            producto.setCantidad(producto.getCantidad() + detalle.getCantidad());            if (producto.getEstadoProducto() == Producto.EstadoProducto.AGOTADO) {                producto.setEstadoProducto(Producto.EstadoProducto.ACTIVO);            }        }    }    private BigDecimal calcularTotal(List<OrdenDetalle> detalles) {        return detalles.stream()                .map(OrdenDetalle::getSubtotal)                .reduce(BigDecimal.ZERO, BigDecimal::add);    }}